const tasks = $input.all();

// Ordena pelo nome completo
tasks.sort((a, b) => a.json.name.localeCompare(b.json.name));

// Base do menor orderindex existente
const base = parseFloat(
  [...tasks]
    .map(t => parseFloat(t.json.orderindex))
    .sort((a, b) => a - b)[0]
);

return tasks.map((item, index) => ({
  json: {
    id: item.json.id,
    name: item.json.name,
    oldOrderIndex: item.json.orderindex,

    // Incrementa de 0.5 preservando o formato
    newOrderIndex: (base + (index * 0.5)).toFixed(34)
  }
}));

