const tasks = $input.all();

tasks.sort((a, b) => a.json.name.localeCompare(b.json.name));

const result = [];

for (let index = 0; index < tasks.length; index++) {
  const current = tasks[index].json;
  const above = index > 0 ? result[index - 1].json : null;
  const below = index < tasks.length - 1 ? tasks[index + 1].json : null;

  let newIndex;

  if (!above && below) {
    newIndex = (parseFloat(below.json?.old_index ?? below.orderindex) - 0.5).toFixed(34);
  } else if (above && !below) {
    newIndex = (parseFloat(above.new_index) + 0.5).toFixed(34);
  } else if (above && below) {
    newIndex = (
      (parseFloat(above.new_index) + parseFloat(below.orderindex)) / 2
    ).toFixed(34);
  } else {
    newIndex = current.orderindex;
  }

  result.push({
    json: {
      position: index + 1,
      name: current.name,
      id: current.id,

      old_index: current.orderindex,
      new_index: newIndex,

      taskAbove: above?.name ?? null,
      taskAboveId: above?.id ?? null,

      taskBelow: below?.name ?? null,
      taskBelowId: below?.id ?? null,

      above: above?.new_index ?? "",

      old_parent: current.parent,
      new_parent: current.parent,

      invalid_index: false
    }
  });
}

return result;
